// mm/src/steps/completeOrderStep.js
import React, { useMemo } from 'react';
import { useWorkflow } from '../store/workflowContext';

import PackageSelector from '../components/packageSelector.js';
import OrderSummary from '../components/orderSummary.js';
import PaymentDelivery from '../components/paymentDelivery.js';

const PACKAGE_PRICES = {
  basic: 49,
  standard: 99,
  premium: 199,
};

export default function CompleteOrderStep() {
  const { bookDetails, details, design, order, setOrder } = useWorkflow();

  const bookTitle = bookDetails?.title || '';
  const pkgId = order?.packageId || 'standard';
  const total = PACKAGE_PRICES[pkgId] ?? 0;

  const isPaid = order?.paymentStatus === 'paid';

  const checkoutPayload = useMemo(() => {
    return () => ({
      bookTitle: bookDetails?.title || '',
      authorName: bookDetails?.author || '',

      author: {
        prefix: details?.prefix || '',
        firstName: details?.firstName || '',
        middleName: details?.middleName || '',
        lastName: details?.lastName || '',
        suffix: details?.suffix || '',
      },

      targetAudience: {
        ageRanges: details?.ageRanges || [],
        demographics: details?.demographics || [],
      },

      publishing: {
        distributionChannels: details?.distributionChannels || [],
        publishingTimeline: details?.publishingTimeline || '',
        authorExperienceLevel: details?.authorExperienceLevel || '',
      },

      additional: {
        marketPositioning: details?.marketPositioning || '',
        seriesInformation: details?.seriesInformation || '',
        brandingPreferences: details?.brandingPreferences || '',
        marketingObjectives: details?.marketingObjectives || '',
      },

      design: {
        typography: design?.typography || '',
        layout: design?.layout || '',
        trim: design?.trim || '',
      },
    });
  }, [bookDetails, details, design]);

  return (
    <div className="space-y-6">
      {/* ✅ If paid, show a success banner */}
      {isPaid ? (
        <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-5">
          <div className="text-emerald-900 font-semibold text-lg">Payment confirmed ✅</div>
          <div className="text-emerald-800 text-sm mt-1">
            Your files are ready below. You can download them anytime from this page.
          </div>
        </div>
      ) : null}

      {/* Package selector */}
      <div className="border rounded-xl p-6 bg-white">
        <PackageSelector
          value={pkgId}
          onChange={(nextId) =>
            setOrder((prev) => ({
              ...prev,
              packageId: nextId,
            }))
          }
        />
      </div>

      {/* Order summary */}
      <OrderSummary
        bookTitle={bookTitle}
        details={details}
        design={design}
        packageId={pkgId}
        packagePrices={PACKAGE_PRICES}
      />

      {/* Payment & Delivery */}
      {!isPaid ? (
        <PaymentDelivery
          packageId={pkgId}
          packagePrices={PACKAGE_PRICES}
          email={order?.deliveryEmail || ''}
          onEmailChange={(val) =>
            setOrder((prev) => ({
              ...prev,
              deliveryEmail: val,
            }))
          }
          checkoutPayload={checkoutPayload}
        />
      ) : (
        <div className="border rounded-xl p-6 bg-white">
          <h2 className="text-2xl font-semibold text-slate-900 flex items-center gap-2">
            <span className="text-slate-600">💳</span> Payment &amp; Delivery
          </h2>
          <p className="mt-3 text-slate-600 text-sm">
            Paid with delivery email:{' '}
            <span className="font-medium text-slate-900">{order?.deliveryEmail || '—'}</span>
          </p>

          <button
            type="button"
            className="mt-4 px-4 py-2 rounded-md border border-slate-200 text-slate-700 hover:bg-slate-50 text-sm"
            onClick={() =>
              setOrder((prev) => ({
                ...prev,
                // optional: let you re-run checkout if needed
                paymentStatus: 'idle',
              }))
            }
          >
            Need to change email / re-pay?
          </button>
        </div>
      )}

      {/* ✅ DOWNLOADS SECTION (embedded) */}
      <div className="border rounded-xl p-6 bg-white">
        <h2 className="text-2xl font-semibold text-slate-900">Download Your Files</h2>
        <p className="mt-2 text-slate-600">
          Your formatted manuscript and print-ready files will be available here after payment.
        </p>

        {!isPaid ? (
          <div className="mt-5 rounded-lg border border-slate-200 bg-slate-50 p-4 text-sm text-slate-700">
            <span className="font-semibold">Payment required:</span> complete checkout above to unlock downloads.
          </div>
        ) : (
          <div className="mt-6 grid grid-cols-1 md:grid-cols-2 gap-4 text-left">
            <div className="border rounded-lg p-5">
              <div className="font-semibold text-slate-900">Print-ready PDF</div>
              <div className="text-sm text-slate-600 mt-1">Trim size + margins + typography applied</div>
              <button
                type="button"
                className="mt-4 px-4 py-2 rounded-md bg-blue-600 text-white hover:bg-blue-700"
              >
                Download PDF
              </button>
            </div>

            <div className="border rounded-lg p-5">
              <div className="font-semibold text-slate-900">eBook Package</div>
              <div className="text-sm text-slate-600 mt-1">EPUB + cover assets</div>
              <button
                type="button"
                className="mt-4 px-4 py-2 rounded-md bg-blue-600 text-white hover:bg-blue-700"
              >
                Download EPUB
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Small helper footer */}
      <div className="text-xs text-slate-500 text-center">
        Total shown: <span className="font-semibold">${total}</span>
      </div>
    </div>
  );
}
